CreatureListener = {}

function CreatureListener:init()
    CreatureAttackPlayerEvent.registerCallBack(self.onCreatureAttackPlayer)
end

function CreatureListener.onCreatureAttackPlayer(playerId, creatureId)
    local player = PlayerManager:getPlayerByEntityId(playerId)
    if not player then
        return
    end
    local creature = MonsterManager:getMonster(creatureId)
    if not creature then
        return
    end
    creature:attackPlayer(player)
end